// @ts-check

import { AbstractHandler } from './AbstractHandler.js'

/**
 * @typedef {import('../../utils/Command.js').Command} Command
 */

class GetInstanceFieldHandler extends AbstractHandler {
    requiredParametersCount = 2

    constructor() {
        super()
    }

    /**
     * @param {Command} command
     */
    process(command) {
        try {
            this.validate(command, this.requiredParametersCount, this.constructor.name)
            const { payload } = command
            let instance = payload[0]
            if (typeof instance === 'undefined') {
                throw new Error('Instance is undefined')
            }
            if (typeof instance !== 'object') {
                throw new Error('Instance must be an object')
            }
            let field = payload[1]
            let instanceField = instance[field]
            return instanceField
        } catch (error) {
            throw this.process_stack_trace(error, this.constructor.name)
        }
    }
}

export { GetInstanceFieldHandler }
